import{_ as t,c as r,o as a,ae as o}from"./chunks/framework.B7Y1jjX-.js";const h=JSON.parse('{"title":"摇树优化","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/性能优化/摇树优化.md","filePath":"generated-notes/前端/性能优化/摇树优化.md"}'),n={name:"generated-notes/前端/性能优化/摇树优化.md"};function i(p,e,s,l,d,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="摇树优化" tabindex="-1">摇树优化 <a class="header-anchor" href="#摇树优化" aria-label="Permalink to &quot;摇树优化&quot;">​</a></h1><p>引用 <a href="https://link.juejin.cn?target=https%3A%2F%2Fdeveloper.mozilla.org%2Fen-US%2Fdocs%2FGlossary%2FTree_shaking" title="https://developer.mozilla.org/en-US/docs/Glossary/Tree_shaking" target="_blank" rel="noreferrer">MDN 文档</a>：</p><p>&gt; Tree shaking 是一个通常用于描述移除 JavaScript 上下文中的未引用代码（dead code）行为的术语。 &gt; &gt; 它依赖于 ES2015 中的 <code>import</code> 和 <code>export</code> 语句，用来检测代码模块是否被导出、导入，且被 JavaScript 文件使用。</p><p>摇树优化是一种实现<a href="https://link.juejin.cn?target=https%3A%2F%2Fen.wikipedia.org%2Fwiki%2FDead_code_elimination" title="https://en.wikipedia.org/wiki/Dead_code_elimination" target="_blank" rel="noreferrer">移除未引用代码（dead code elimination）</a>的方式，实现的方式是检测哪些导出项（export）在应用代码里未被引用。它会被类似 <a href="https://link.juejin.cn?target=https%3A%2F%2Fwebpack.js.org%2F" title="https://webpack.js.org/" target="_blank" rel="noreferrer">Webpack</a> 和 <a href="https://link.juejin.cn?target=https%3A%2F%2Frollupjs.org%2Fguide%2Fen%2F" title="https://rollupjs.org/guide/en/" target="_blank" rel="noreferrer">Rollup</a> 这样的打包工具执行，最早由 Rollup 实现。</p><p>作者：darkyzhou<br> 链接：<a href="https://juejin.cn/post/6977334810536575013" target="_blank" rel="noreferrer">https://juejin.cn/post/6977334810536575013</a><br> 来源：稀土掘金<br> 著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。</p><p>摇树优化是基于ESM的，也就是CJS以及其他的前端模块化的方式是不能够实现摇树优化的。</p>',6)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
